   488→export interface ShareInfoReturnType {
   489→  [ShareTarget.FOLDER]: IFolderShareInfo;
   490→  [ShareTarget.API_TABLE]: APITableShareInfo;
   491→  [ShareTarget.API_VIEW]: IAPIViewShareInfo;
   492→  [ShareTarget.LUCKY_SHEET]: ILucysheetShareInfo;
   493→  [ShareTarget.AFFINE]: IAffineShareInfo;
   494→  [ShareTarget.OUTLINE]: OutlineShareInfo;
   495→  [ShareTarget.ONLYOFFICE_EXCEL]: IOnlyOfficeShareInfo;
   496→  [ShareTarget.API_TABLE_VIEW_MIRRORS]: never;
   497→  [ShareTarget.API_TABLE_FORMS]: never;
   498→  [ShareTarget.VIEW_MIRROR]: never;
   499→  [ShareTarget.API_FORM]: never;
   500→}
   501→type INodeShareInfoRsp = {
   502→  nodeShareScope: {
   503→    appConfig: string;
   504→  };
   505→  nodeShares?: {
   506→    props: { onlyRead: boolean; canBeEdited: boolean; canBeStored: boolean };
   507→    shareId: string;
   508→    shareType: number;
   509→    isEnabled: boolean;
   510→    appShareUrl: string;
   511→    expireTime?: string | null;
   512→  }[];
   513→  spaceNode?: { type: SpaceTreeNodeType; id: string; appSpaceNodeId: string };
   514→  shareScopes?: {
   515→    appConfig: string;
   516→    shareId: string;
   517→    defaultViewId?: string;
   518→    allowedEmails?: string[];
   519→    isKnockNotifyEnabled?: boolean;
   520→  }[];
   521→};
   522→// 后端props 转换为 permission
   523→const propsToPermission = (v?: NonNullable<INodeShareInfoRsp['nodeShares']>[number]['props']) => {
   524→  if (!v) return null;
   525→  if (v.onlyRead) return SharePermission.VIEW_ABLE;
   526→  if (v.canBeEdited) return SharePermission.EDIT_ABLE;
   527→  if (v.canBeStored) return SharePermission.COPY_ABLE;
   528→  return null;
   529→};
   530→// 后端 nodeShares 转换为 IShareLink
   531→const toLink = (v?: NonNullable<INodeShareInfoRsp['nodeShares']>[number], scope?: NonNullable<INodeShareInfoRsp['shareScopes']>[number]): IShareLink => {
   532→  const appJson = scope?.appConfig ? JSON.parse(scope.appConfig) : {};
   533→  return {
   534→    on: v?.isEnabled ?? false,
   535→    url: v?.appShareUrl ?? '',
   536→    shareId: v?.shareId ?? '',
   537→    expireTime: v?.expireTime ? dayjs(v.expireTime).format('YYYY-MM-DD') : null,
   538→    defaultView: appJson?.defaultViewId ?? undefined,
   539→  };
   540→};
   541→// 后端 nodeShares、shareScopes 转换为 IDesignateShareLink
   542→const toDesignateUser = (v: INodeShareInfoRsp['nodeShares'], shareScopes: INodeShareInfoRsp['shareScopes']) => {
   543→  return filterNone((v || []).map((o): IDesignateShareLink | null => {
   544→    const t = arrFind(shareScopes ?? [], 'shareId', o.shareId);
   545→    if (!t) return null;
   546→    const permission = propsToPermission(o.props);
   547→    if (!permission) return null;
   548→    return {
   549→      shareId: t.shareId,
   550→      on: o.isEnabled,
   551→      url: o.appShareUrl,
   552→      permission,
   553→      emails: t.allowedEmails ?? [],
   554→      knockNotify: t.isKnockNotifyEnabled ?? false,
   555→      expireTime: o?.expireTime ? dayjs(o.expireTime).format('YYYY-MM-DD') : null,
   556→    };
   557→  }));
   558→};
   559→// 获取节点分享信息
   560→export function getAPITableNodeShareInfo<T extends ShareTarget>(
   561→  nodeId: string,
   562→  spaceId: string,
   563→  target: T,
   564→): Promise<ShareInfoReturnType[T]> {
   565→  return fetchData<void, INodeShareInfoRsp>({
   566→    url: `/api/v1/node/${nodeId}/getNodeShare`,
   567→    headers: {
   568→      'x-space-id': spaceId,
   569→    },
   570→  }).then((r) => {
   571→    const viewT = r?.nodeShares?.find((o) => o.props.onlyRead && o.shareType === 1);
   572→    const editT = r?.nodeShares?.find((o) => o.props.canBeEdited && o.shareType === 1);
   573→    const copyT = r?.nodeShares?.find((o) => o.props.canBeStored && o.shareType === 1);
   574→    const type2T = r?.nodeShares?.filter((o) => o.shareType === 2) ?? [];
   575→    if (target === ShareTarget.AFFINE) {
   576→      const result: IAffineShareInfo = {
   577→        type: ShareTarget.AFFINE,
   578→        data: {
   579→          nodeId,
   580→          link: {
   581→            [SharePermission.VIEW_ABLE]: toLink(viewT),
   582→            [SharePermission.COPY_ABLE]: toLink(copyT),
   583→            [SharePermission.EDIT_ABLE]: toLink(editT),
   584→          },
   585→          designateUser: toDesignateUser(type2T, r.shareScopes),
   586→        },
   587→      };
   588→      return result;
   589→    }
   590→    if (target === ShareTarget.API_TABLE) {
   591→      const viewScopeT = viewT ? (arrFind(r.shareScopes || [], 'shareId', viewT.shareId) ?? undefined) : undefined;
   592→      const editScopeT = editT ? (arrFind(r.shareScopes || [], 'shareId', editT.shareId) ?? undefined) : undefined;
   593→      const copyScopeT = copyT ? (arrFind(r.shareScopes || [], 'shareId', copyT.shareId) ?? undefined) : undefined;
   594→      return {
   595→        type: ShareTarget.API_TABLE,
   596→        data: {
   597→          nodeId: r.spaceNode?.id ?? '',
   598→          APINodeId: r.spaceNode?.appSpaceNodeId ?? '',
   599→          shareRange: true,
   600→          link: {
   601→            [SharePermission.VIEW_ABLE]: toLink(viewT, viewScopeT),
   602→            [SharePermission.EDIT_ABLE]: toLink(editT, editScopeT),
   603→            [SharePermission.COPY_ABLE]: toLink(copyT, copyScopeT),
   604→          },
   605→          designateUser: toDesignateUser(type2T, r.shareScopes),
   606→        },
   607→      } as APITableShareInfo;
   608→    }
   609→    if (target === ShareTarget.LUCKY_SHEET) {
   610→      const result: ILucysheetShareInfo = {
   611→        type: ShareTarget.LUCKY_SHEET,
   612→        data: {
   613→          nodeId,
   614→          link: {
   615→            [SharePermission.VIEW_ABLE]: toLink(viewT),
   616→            [SharePermission.EDIT_ABLE]: toLink(editT),
   617→          },
   618→        },
   619→      };
   620→      return result;
   621→    }
   622→    if (target === ShareTarget.API_VIEW) {
   623→      const result: IAPIViewShareInfo = {
   624→        type: ShareTarget.API_VIEW,
   625→        nodeId,
   626→        data: (r.shareScopes || []).reduce((prev, curr) => {
   627→          const appConfig = JSON.parse(curr.appConfig);
   628→          if (appConfig?.viewIds?.length !== 1) {
   629→            return prev;
   630→          }
   631→          const viewId = appConfig.viewIds[0] as string;
   632→          const { shareId } = curr;
   633→          const tarNodeS = r.nodeShares?.find((o) => o.shareId === shareId);
   634→          if (!tarNodeS) return prev;
   635→          const permission = propsToPermission(tarNodeS.props);
   636→          if (!permission) return prev;
   637→          if (!prev[viewId]) {
   638→            prev[viewId] = {
   639→              APIViewId: viewId, APIViewName: '', link: {},
   640→            };
   641→          }
   642→          prev[viewId].link[permission] = toLink(tarNodeS);
   643→          // {
   644→          //   on: tarNodeS.isEnabled, shareId: tarNodeS.shareId, url: tarNodeS.appShareUrl,
   645→          // };
   646→          return prev;
   647→        }, {} as IAPIViewShareInfo['data']),
   648→      };
   649→      return result;
   650→    }
   651→    if (target === ShareTarget.OUTLINE) {
   652→      return {
   653→        type: ShareTarget.OUTLINE,
   654→        data: {
   655→          link: {
   656→            [SharePermission.VIEW_ABLE]: toLink(viewT),
   657→            [SharePermission.EDIT_ABLE]: toLink(editT),
   658→            [SharePermission.COPY_ABLE]: toLink(copyT),
   659→          },
   660→        },
   661→      };
   662→    }
   663→    if (target === ShareTarget.ONLYOFFICE_EXCEL) {
   664→      const result: IOnlyOfficeShareInfo = {
   665→        type: ShareTarget.ONLYOFFICE_EXCEL,
   666→        data: {
   667→          nodeId: r.spaceNode?.appSpaceNodeId ?? '',
   668→          link: {
   669→            [SharePermission.VIEW_ABLE]: toLink(viewT),
   670→            [SharePermission.EDIT_ABLE]: toLink(editT),
   671→            [SharePermission.COPY_ABLE]: toLink(copyT),
   672→          },
   673→          designateUser: toDesignateUser(type2T, r.shareScopes),
   674→        },
   675→      };
   676→      return result;
   677→    }
   678→    if (target === ShareTarget.FOLDER) {
   679→      const fViewT = r?.nodeShares?.find((o) => o.props.onlyRead && o.shareType === 4);
   680→      const fEditT = r?.nodeShares?.find((o) => o.props.canBeEdited && o.shareType === 4);
   681→      const fCopyT = r?.nodeShares?.find((o) => o.props.canBeStored && o.shareType === 4);
   682→      const fType2T = r?.nodeShares?.filter((o) => o.shareType === 5) ?? [];
   683→
   684→      return {
   685→        type: ShareTarget.FOLDER,
   686→        data: {
   687→          link: {
   688→            [SharePermission.VIEW_ABLE]: toLink(fViewT),
   689→            [SharePermission.EDIT_ABLE]: toLink(fEditT),
   690→            [SharePermission.COPY_ABLE]: toLink(fCopyT),
   691→          },
   692→          designateUser: toDesignateUser(fType2T, r.shareScopes),
   693→        },
   694→      };
   695→    }
   696→    throw new Error(`Unsupported share target: ${target}`);
   697→  }) as Promise<ShareInfoReturnType[T]>;
   698→};
