   952→const toSubmitSetting = (v?: null | string) => {
   953→  const appConfig = !v ? null : JSON.parse(v);
   954→  if (!appConfig) return 'anonymous';
   955→  if (!appConfig.fillAnonymous && appConfig.submitLimit === 1) return 'onlyOnce';
   956→  if (!appConfig.fillAnonymous && appConfig.submitLimit === 0) return 'noLimit';
   957→  if (appConfig.fillAnonymous && appConfig.submitLimit === 0) return 'anonymous';
   958→  return 'anonymous';
   959→};
   960→
   961→const submitSettingTo = (v?: IFormShareLink['submitSetting']): {
   962→  submitLimit: 0 | 1;
   963→  fillAnonymous: boolean;
   964→} => {
   965→  return {
   966→    submitLimit: (v === 'anonymous' || v === 'noLimit' || !v) ? 0 : 1,
   967→    fillAnonymous: (v === 'anonymous' || !v) ? true : false,
   968→  };
   969→};
