   980→export function batchGetAPITableNodeShareInfo(dstId: string, spaceId: string, target: ShareTarget.API_FORM | ShareTarget.VIEW_MIRROR): Promise<{
   981→  shareInfo: IAPIFormShareInfo | IAPIMirrorShareInfo;
