   997→      const targetS = r?.[0].nodeShares?.find((o) => o.props.canBeEdited);
   998→      const nodeShareScope = r?.[0].nodeShareScope;
   999→      const submitSetting = toSubmitSetting(nodeShareScope?.appConfig);
