     1→import { CaretRightFilled } from '@ant-design/icons';
     2→import { skipToken } from '@reduxjs/toolkit/query';
     3→import { Avatar, Button, Flex } from 'antd';
     4→import React, { useEffect, useMemo, useState } from 'react';
     5→
     6→import { ListItem } from '@/components/ListItem';
     7→import { getAvatarRandomColor } from '@/components/UserAvatar';
     8→import { useGetSpaceNodeTreeQuery } from '@/store/query/node';
     9→import { ISpace, ISpaceTreeNode } from '@/types/space';
    10→import { traversalTree } from '@/utils/tree';
    11→
    12→import { ISpaceTreeNodeProps, SpaceTreeNodeListItem } from './SpaceTreeNodeListItem';
    13→import { ISpacesTreeProps } from './type';
    14→
    15→interface ISpaceTreeProps<T> extends Omit<ISpacesTreeProps<T>, 'sortSpace' | 'defaultExpandSpaceId'> {
    16→  space: ISpace;
    17→  defaultExpand?: boolean;
    18→}
    19→
    20→export const SpaceTree: <T = void>(props: ISpaceTreeProps<T>) => React.ReactNode = <T,>({
    21→  defaultExpand = false,
    22→  space,
    23→  getSpaceTreeNodeProps,
    24→  renderSpaceTreeNode,
    25→  selectedKeys,
    26→  onClick,
    27→  defaultExpandSpaceNodeId,
    28→  defaultExpandTree,
    29→  getSpaceCtx,
    30→}: ISpaceTreeProps<T>) => {
    31→  const [expand, setExpand] = useState(defaultExpand);
    32→  const { data: spaceNodeTree, isLoading } = useGetSpaceNodeTreeQuery(expand ? space.spaceId : skipToken);
    33→  const [expandedKeys, setExpandedKeys] = useState<string[]>([]); // spaceNodeId
    34→
    35→  const defaultExpandedRef = React.useRef(false);
    36→
    37→  useEffect(() => {
    38→    if (!spaceNodeTree || defaultExpandedRef.current) return;
    39→    defaultExpandedRef.current = true;
    40→    if (defaultExpandTree) {
    41→      const keys = new Set<string>();
    42→      traversalTree(spaceNodeTree.tree, (node) => {
    43→        if (node.children.length > 0) keys.add(node.id);
    44→      });
    45→      setExpandedKeys((old) => [...new Set([...old, ...keys])]);
    46→    } else if (selectedKeys?.length) {
    47→      // 默认展开selectedKeys的所有父节点
    48→      const keys = new Set<string>();
    49→      for (const key of selectedKeys) {
    50→        let currNode = spaceNodeTree.spaceNodeMap[key];
    51→
    52→        while (currNode && currNode.parentId !== '0') {
    53→          const parentNode = spaceNodeTree.treeNodeMap[currNode.parentId];
    54→          if (!parentNode) break;
    55→          keys.add(parentNode.id);
    56→          currNode = parentNode;
    57→        }
    58→      }
    59→      setExpandedKeys([...keys]);
    60→    }
    61→  }, [defaultExpandTree, selectedKeys, spaceNodeTree]);
    62→
    63→  useEffect(() => {
    64→    if (!spaceNodeTree || !defaultExpand || !defaultExpandSpaceNodeId) return;
    65→    setExpandedKeys((old) => {
    66→      const newSet = new Set<string>(old);
    67→      let currNode = spaceNodeTree.spaceNodeMap[defaultExpandSpaceNodeId];
    68→      while (currNode && currNode.parentId !== '0') {
    69→        newSet.add(currNode.id);
    70→        currNode = spaceNodeTree.treeNodeMap[currNode.parentId];
    71→      }
    72→      return [...newSet];
    73→    });
    74→  }, [defaultExpandSpaceNodeId, spaceNodeTree, defaultExpand]);
    75→
    76→  const flatTree = useMemo(() => {
    77→    if (!spaceNodeTree || !expand) return [];
    78→    const result: ISpaceTreeNode[] = [];
    79→    traversalTree(spaceNodeTree.tree, (node) => {
    80→      result.push(node);
    81→      if (!expandedKeys.includes(node.id)) return { preventChildren: true };
    82→    });
    83→    return result;
    84→  }, [expand, expandedKeys, spaceNodeTree]);
    85→
    86→  const spaceCtx = useMemo(() => {
    87→    if (!getSpaceCtx) return undefined as T;
    88→    return getSpaceCtx({
    89→      spaceNodeTree,
    90→      expand,
    91→      expandedKeys,
    92→      setExpandedKeys,
    93→    });
    94→  }, [expand, expandedKeys, getSpaceCtx, spaceNodeTree]);
    95→
    96→  return (
    97→    <>
    98→      <ListItem
    99→        data-key={space.spaceId}
   100→        data-space-id={space.spaceId}
   101→        data-type="space"
   102→        className="aio-space-tree-node"
   103→        active={selectedKeys?.includes(space.spaceId)}
   104→        onClick={(e) => {
   105→          onClick?.(e, { type: 'space', data: space });
   106→          if (!e.defaultPrevented) {
   107→            setExpand((old) => !old);
   108→          }
   109→        }}
   110→        prefixNode={(
   111→          <Button
   112→            type="text"
   113→            size="small"
   114→            icon={<CaretRightFilled rotate={expand ? 90 : 0} />}
   115→            loading={isLoading}
   116→            onClick={(e) => {
   117→              e.preventDefault();
   118→              e.stopPropagation();
   119→              setExpand((old) => !old);
   120→            }}
   121→          />
   122→        )}
   123→      >
   124→        <Flex align="center" gap={8}>
   125→          <Avatar
   126→            shape="square"
   127→            size={16}
   128→            style={{ backgroundColor: getAvatarRandomColor(space.spaceId), flexShrink: 0 }}
   129→          >
   130→            {space.name[0]}
   131→          </Avatar>
   132→          <div className="text-ellipsis">
   133→            {space.name}
   134→          </div>
   135→        </Flex>
   136→      </ListItem>
   137→      {flatTree.map((it) => {
   138→        const toggleExpanded = () => {
   139→          setExpandedKeys((old) => {
   140→            const newSet = new Set(old);
   141→            newSet[newSet.has(it.id) ? 'delete' : 'add'](it.id);
   142→            return [...newSet];
   143→          });
   144→        };
   145→        let listItemProps: ISpaceTreeNodeProps = {
   146→          node: it,
   147→          expanded: expandedKeys.includes(it.id),
   148→          active: selectedKeys?.includes(it.id),
   149→          onClick: (e) => {
   150→            onClick?.(e, { type: 'node', data: it });
   151→            if (!e.defaultPrevented) {
   152→              toggleExpanded();
   153→            }
   154→          },
   155→          toggleExpanded,
   156→        };
   157→        if (getSpaceTreeNodeProps) {
   158→          listItemProps = getSpaceTreeNodeProps({ type: 'node', data: it }, {
   159→            ...spaceCtx,
   160→            expandedKeys,
   161→            setExpandedKeys,
   162→            originalProps: listItemProps,
   163→            spaceNodeTree,
   164→            expand,
   165→          });
   166→        }
   167→        let listItemNode: React.ReactNode = (
   168→          <SpaceTreeNodeListItem
   169→            {...listItemProps}
   170→            data-key={it.data.id}
   171→            data-space-id={space.spaceId}
   172→            data-tree-node-id={it.id}
   173→            data-space-node-id={it.data.id}
   174→            data-type="node"
   175→          />
   176→        );
   177→        if (renderSpaceTreeNode) {
   178→          listItemNode = renderSpaceTreeNode({ type: 'node', data: it }, {
   179→            ...spaceCtx,
   180→            expandedKeys,
   181→            setExpandedKeys,
   182→            originalNode: listItemNode,
   183→            spaceNodeTree,
   184→            expand,
   185→          });
   186→        }
   187→        return listItemNode;
   188→      })}
   189→    </>
   190→  );
   191→};
