   162→/** 将ISpaceTree数据转换成ISpaceTreeNode树节点对象，在原对象上改动，不生成新对象 */
   163→export function createSpaceTreeNode(
   164→  data: ISpaceTree,
   165→  map: Record<string, ISpaceTreeNode | undefined>,
   166→): ISpaceTreeNode {
   167→  const node = data as ISpaceTreeNode;
   168→  // 不要在node中添加parent对象引用，使用parentId从nodeMap中获取
   169→  const parent: ISpaceTreeNode | undefined = map[node.parentId];
   170→  node.depth = (parent?.depth ?? -1) + 1;
   171→  return node;
   172→}
   173→
   174→/** ISpaceTree树转换成ISpaceTreeNode树，在原对象上改动 */
   175→export function resolveSpaceTree(tree: ISpaceTree[]) {
   176→  const treeNodeMap: Record<string, ISpaceTreeNode> = {};
   177→  const spaceNodeMap: Record<string, ISpaceTreeNode> = {};
   178→  traversalTree(tree as ISpaceTreeNode[], (node) => {
   179→    createSpaceTreeNode(node, treeNodeMap);
   180→    treeNodeMap[node.id] = node;
   181→    spaceNodeMap[node.data.id] = node;
   182→  });
   183→  return {
   184→    tree: tree as ISpaceTreeNode[],
   185→    treeNodeMap,
   186→    spaceNodeMap,
   187→  };
   188→}
