    67→    const applyChange = (spaceNode: ISpaceNode) => {
    68→      spaceNode.updatedAt = new Date(data.data.updatedAt).getTime();
    69→      spaceNode.name = data.data.name;
    70→      spaceNode.icon = data.data.icon;
    71→    };
    72→    affect.forEach((it) => {
