    74→        dispatch((aioApi as typeof spaceNodeApi).util.updateQueryData(it.endpointName, it.originalArgs, (draft) => {
    75→          if (!draft?.data?.id) return;
    76→          applyChange(draft.data);
    77→        }));
    78→      } else if (it.endpointName === 'getSpaceNodeTree') {
    79→        const cache = (aioApi as typeof spaceNodeApi).endpoints.getSpaceNodeTree.select(it.originalArgs)(state);
